"""
AST node definitions for the pipeline DSL.
"""

from dataclasses import dataclass, field
from typing import List, Optional, Any, Dict


# ============ Parameter Nodes ============

@dataclass
class Parameter:
    name: str
    type_name: str  # 'string', 'int', 'float', 'bool', 'list[T]'
    inner_type: Optional[str] = None  # For list[T], the T
    default_value: Any = None
    has_default: bool = False
    env_var: Optional[str] = None  # If default comes from env var


# ============ Expression Nodes ============

@dataclass
class Expr:
    pass

@dataclass
class IntLiteral(Expr):
    value: int

@dataclass
class FloatLiteral(Expr):
    value: float

@dataclass
class StringLiteral(Expr):
    value: str

@dataclass
class BoolLiteral(Expr):
    value: bool

@dataclass
class ListLiteral(Expr):
    elements: List[Expr]

@dataclass
class IdentifierExpr(Expr):
    name: str

@dataclass
class ArrayIndexExpr(Expr):
    array: Expr
    index: Expr

@dataclass
class DollarVar(Expr):
    value: str  # e.g. "${params.x}" or "$VAR"

@dataclass
class BinaryExpr(Expr):
    op: str  # '+', '-', '*', '/', '%', '==', '!=', '<', '>', '<=', '>=', '&&', '||'
    left: Expr
    right: Expr

@dataclass
class UnaryExpr(Expr):
    op: str  # '!', '-'
    operand: Expr

@dataclass
class FunctionCallExpr(Expr):
    name: str
    args: List[Expr]

@dataclass
class AssignmentExpr(Expr):
    type_name: Optional[str]  # None for simple assignment, type name for declaration
    name: str
    value: Expr


# ============ Statement Nodes ============

@dataclass
class Stmt:
    pass

@dataclass
class ExprStmt(Stmt):
    expr: Expr

@dataclass
class ReturnStmt(Stmt):
    value: Expr

@dataclass
class BreakStmt(Stmt):
    pass

@dataclass
class ContinueStmt(Stmt):
    pass

@dataclass
class BlockStmt(Stmt):
    statements: List[Stmt]

@dataclass
class IfStmt(Stmt):
    condition: Expr
    then_block: BlockStmt
    elif_clauses: List[tuple]  # List of (condition, block)
    else_block: Optional[BlockStmt]

@dataclass
class ForStmt(Stmt):
    init: Optional[Stmt]
    condition: Optional[Expr]
    update: Optional[Stmt]
    body: BlockStmt

@dataclass
class WhileStmt(Stmt):
    condition: Expr
    body: BlockStmt

@dataclass
class TaskCallStmt(Stmt):
    task_name: str
    positional_args: List[Expr]
    named_args: Dict[str, Expr]

@dataclass
class FailsStmt(Stmt):
    task_call: TaskCallStmt


# ============ Task Definition ============

@dataclass
class TaskDef:
    name: str
    params: List[Parameter]
    run_block: Optional[str]  # Raw command string
    success_block: Optional[Dict[str, 'SuccessBlock']]  # name -> block of statements
    requires_block: Optional[List[Stmt]]
    output: Optional[Expr]
    timeout: Optional[float]


@dataclass
class SuccessBlock:
    statements: List[Stmt]
    is_multiline: bool  # True if block has multiple statements/return


# ============ Pipeline ============

@dataclass
class Pipeline:
    tasks: Dict[str, TaskDef]

"""
Configuration file parser for TOML config.
"""

import os
import re
import toml
from typing import Dict, Any, Optional, Tuple, List
from dataclasses import dataclass


@dataclass
class Config:
    entry: Optional[str] = None  # Task name or task call like "A(1, x=2)"
    clean_cwd: bool = False
    env: Dict[str, str] = None

    def __post_init__(self):
        if self.env is None:
            self.env = {}


class ConfigParseError(Exception):
    pass


def parse_config(config_path: str) -> Config:
    """Parse a TOML configuration file."""
    if not os.path.exists(config_path):
        raise ConfigParseError(f"SYNTAX_ERROR: Config file not found: {config_path}")

    try:
        with open(config_path, 'r') as f:
            data = toml.load(f)
    except toml.TomlDecodeError as e:
        raise ConfigParseError(f"SYNTAX_ERROR: Invalid TOML: {e}")

    entry = data.get('entry')
    clean_cwd = data.get('clean_cwd', False)
    env = data.get('env', {})

    return Config(entry=entry, clean_cwd=clean_cwd, env=env)


def parse_entry_call(entry: str) -> Tuple[str, List[Any], Dict[str, Any]]:
    """
    Parse an entry call like "A" or "A(1, x=2)" into (task_name, positional_args, named_args).

    Args:
        entry: Entry string like "A" or "A(1, x=2)"

    Returns:
        Tuple of (task_name, positional_args, named_args)
    """
    if entry is None:
        return None, [], {}

    # Check if it has arguments
    match = re.match(r'^(\w+)(?:\((.*)\))?$', entry.strip())
    if not match:
        raise ConfigParseError(f"SYNTAX_ERROR: Invalid entry format: {entry}")

    task_name = match.group(1)
    args_str = match.group(2)

    if args_str is None:
        return task_name, [], {}

    positional_args = []
    named_args = {}

    # Parse arguments
    args_str = args_str.strip()
    if args_str:
        # Split by comma, but respect nested structures
        parts = split_args(args_str)

        for part in parts:
            part = part.strip()
            if '=' in part:
                # Named argument
                eq_pos = part.index('=')
                name = part[:eq_pos].strip()
                value_str = part[eq_pos + 1:].strip()
                value = parse_value(value_str)
                named_args[name] = value
            else:
                # Positional argument
                value = parse_value(part)
                positional_args.append(value)

    return task_name, positional_args, named_args


def split_args(args_str: str) -> List[str]:
    """Split arguments by comma, respecting nested structures."""
    parts = []
    current = []
    depth = 0
    in_string = False
    string_char = None

    i = 0
    while i < len(args_str):
        ch = args_str[i]

        if in_string:
            current.append(ch)
            if ch == string_char and (i == 0 or args_str[i-1] != '\\'):
                in_string = False
        elif ch in '"\'':
            in_string = True
            string_char = ch
            current.append(ch)
        elif ch in '([{':
            depth += 1
            current.append(ch)
        elif ch in ')]}':
            depth -= 1
            current.append(ch)
        elif ch == ',' and depth == 0:
            parts.append(''.join(current))
            current = []
        else:
            current.append(ch)

        i += 1

    if current:
        parts.append(''.join(current))

    return parts


def parse_value(value_str: str) -> Any:
    """Parse a value string into a Python value."""
    value_str = value_str.strip()

    # Boolean
    if value_str.lower() == 'true':
        return True
    if value_str.lower() == 'false':
        return False

    # String (quoted)
    if (value_str.startswith('"') and value_str.endswith('"')) or \
       (value_str.startswith("'") and value_str.endswith("'")):
        return value_str[1:-1]

    # Integer
    try:
        return int(value_str)
    except ValueError:
        pass

    # Float
    try:
        return float(value_str)
    except ValueError:
        pass

    # List
    if value_str.startswith('[') and value_str.endswith(']'):
        inner = value_str[1:-1].strip()
        if not inner:
            return []
        parts = split_args(inner)
        return [parse_value(p) for p in parts]

    # Default to string
    return value_str

"""
Task executor for running pipeline tasks.
"""

import os
import sys
import json
import time
import subprocess
import shutil
from typing import Dict, List, Any, Optional, Tuple
from dataclasses import dataclass, field, asdict
from .ast_nodes import (
    TaskDef, Parameter, TaskCallStmt, FailsStmt, DollarVar
)
from .evaluator import RequiresEvaluator, SuccessEvaluator


@dataclass
class JobResult:
    job_id: int
    task: str
    params: Dict[str, Any]
    stdout: str
    stderr: str
    timed_out: bool
    success: Dict[str, bool]
    output: Optional[str]
    exit_code: int
    parent: Optional[int]
    duration: float

    def to_dict(self) -> dict:
        return {
            "job_id": self.job_id,
            "task": self.task,
            "params": self.params,
            "stdout": self.stdout,
            "stderr": self.stderr,
            "timed_out": self.timed_out,
            "success": self.success,
            "output": self.output,
            "exit_code": self.exit_code,
            "parent": self.parent,
            "duration": self.duration
        }


class TaskExecutor:
    def __init__(self, pipeline, workspace: str, output_dir: str, env_vars: Dict[str, str],
                 clean_cwd: bool = False):
        self.pipeline = pipeline
        self.workspace = os.path.abspath(workspace)
        self.output_dir = os.path.abspath(output_dir)
        self.env_vars = env_vars
        self.clean_cwd = clean_cwd
        self.job_counter = 0
        self.job_results: List[JobResult] = []
        self.call_stack: set = set()  # Track task calls to detect recursion

    def log_event(self, event: str, job_id: int, **kwargs):
        """Log event to stdout as JSON."""
        data = {"event": event, "job_id": job_id, **kwargs}
        print(json.dumps(data))
        sys.stdout.flush()

    def validate_params(self, task: TaskDef, positional_args: List[Any],
                        named_args: Dict[str, Any]) -> Dict[str, Any]:
        """Validate and resolve parameters for a task call."""
        params = {}

        # Check for parameters with defaults first
        has_default_seen = False
        for i, param in enumerate(task.params):
            if param.has_default:
                has_default_seen = True
            elif has_default_seen and not param.has_default:
                raise ValueError(f"SYNTAX_ERROR: Parameter '{param.name}' without default follows one with default")

        # Process positional args
        if len(positional_args) > len(task.params):
            raise ValueError(f"INVALID_PIPE: Too many arguments for task '{task.name}'")

        for i, value in enumerate(positional_args):
            param = task.params[i]
            params[param.name] = self.validate_param_type(param, value)

        # Process named args
        for name, value in named_args.items():
            param_def = None
            for p in task.params:
                if p.name == name:
                    param_def = p
                    break
            if param_def is None:
                raise ValueError(f"INVALID_PIPE: Unknown parameter '{name}' for task '{task.name}'")
            if name in params:
                raise ValueError(f"INVALID_PIPE: Duplicate parameter '{name}'")
            params[name] = self.validate_param_type(param_def, value)

        # Fill in defaults for missing parameters
        for param in task.params:
            if param.name not in params:
                if param.has_default:
                    if param.env_var:
                        # Resolve from environment
                        env_value = self.env_vars.get(param.env_var.lstrip('${').rstrip('}'))
                        if env_value is None:
                            env_value = os.environ.get(param.env_var.lstrip('$'))
                        if env_value is None:
                            raise ValueError(f"INVALID_PIPE: Environment variable '{param.env_var}' not set")
                        params[param.name] = self.cast_env_value(env_value, param.type_name)
                    else:
                        params[param.name] = param.default_value
                else:
                    raise ValueError(f"INVALID_PIPE: Missing required parameter '{param.name}'")

        return params

    def validate_param_type(self, param: Parameter, value: Any) -> Any:
        """Validate and cast a parameter value to the expected type."""
        type_name = param.type_name

        if type_name == 'string':
            return str(value)
        elif type_name == 'int':
            if isinstance(value, bool):
                return int(value)
            if isinstance(value, (int, float)):
                return int(value)
            raise ValueError(f"INVALID_PIPE: Cannot convert {type(value).__name__} to int")
        elif type_name == 'float':
            if isinstance(value, (int, float)):
                return float(value)
            raise ValueError(f"INVALID_PIPE: Cannot convert {type(value).__name__} to float")
        elif type_name == 'bool':
            if isinstance(value, bool):
                return value
            if isinstance(value, (int, float)):
                return bool(value)
            if isinstance(value, str):
                if value.lower() == 'true':
                    return True
                elif value.lower() == 'false':
                    return False
                return bool(value)
            raise ValueError(f"INVALID_PIPE: Cannot convert {type(value).__name__} to bool")
        elif type_name.startswith('list['):
            if isinstance(value, list):
                inner_type = param.inner_type
                return [self.cast_value(v, inner_type) for v in value]
            raise ValueError(f"INVALID_PIPE: Expected list, got {type(value).__name__}")

        return value

    def cast_value(self, value: Any, type_name: str) -> Any:
        """Cast a value to the specified type."""
        if type_name == 'string':
            return str(value)
        elif type_name == 'int':
            return int(value)
        elif type_name == 'float':
            return float(value)
        elif type_name == 'bool':
            if isinstance(value, str):
                return value.lower() == 'true'
            return bool(value)
        return value

    def cast_env_value(self, value: str, type_name: str) -> Any:
        """Cast an environment variable value to the expected type."""
        if type_name == 'string':
            return value
        elif type_name == 'int':
            return int(value)
        elif type_name == 'float':
            return float(value)
        elif type_name == 'bool':
            if value.lower() in ('true', '1', 'yes'):
                return True
            return False
        elif type_name.startswith('list['):
            # Parse comma-separated list
            return [v.strip() for v in value.split(',')]
        return value

    def resolve_run_command(self, run_block: str, params: Dict[str, Any],
                            output_dir: Optional[str]) -> str:
        """Resolve parameters in run command."""
        command = run_block

        # Replace ${params.x} with parameter values
        for name, value in params.items():
            command = command.replace(f'${{params.{name}}}', str(value))

        # Replace ${workspace}
        command = command.replace('${workspace}', self.workspace)

        # Replace ${output}
        if output_dir:
            command = command.replace('${output}', output_dir)

        return command

    def run_command(self, command: str, cwd: str, timeout: Optional[float] = None) -> Tuple[str, str, int, bool]:
        """Run a shell command and return stdout, stderr, exit_code, timed_out."""
        try:
            result = subprocess.run(
                command,
                shell=True,
                capture_output=True,
                text=True,
                cwd=cwd,
                timeout=timeout
            )
            stdout = result.stdout
            stderr = result.stderr
            exit_code = result.returncode
            timed_out = False
        except subprocess.TimeoutExpired:
            stdout = ""
            stderr = ""
            exit_code = 124
            timed_out = True

        # Clean up stdout/stderr
        stdout = self.clean_output(stdout)
        stderr = self.clean_output(stderr)

        return stdout, stderr, exit_code, timed_out

    def clean_output(self, text: str) -> str:
        """Clean output text - replace special characters."""
        text = text.replace('\u2018', "'")
        text = text.replace('\u2019', "'")
        return text

    def resolve_output_path(self, output_expr, params: Dict[str, Any]) -> Optional[str]:
        """Resolve output directory path."""
        if output_expr is None:
            return None

        # Evaluate the output expression
        from .evaluator import Evaluator
        evaluator = Evaluator(
            variables={'params': params},
            env_vars=self.env_vars,
            workspace=self.workspace
        )

        output_str = evaluator.evaluate_expr(output_expr)

        if output_str is None:
            return None

        # Handle ${workspace} prefix
        if isinstance(output_str, str) and '${workspace}' in output_str:
            output_str = output_str.replace('${workspace}', self.workspace)
            return output_str

        # Make absolute path
        if os.path.isabs(output_str):
            return output_str

        return os.path.join(self.workspace, output_str)

    def validate_path_in_workspace(self, path: str) -> bool:
        """Check that a path is within the workspace."""
        abs_path = os.path.abspath(path)
        return abs_path.startswith(self.workspace)

    def execute_task_call(self, task_call: TaskCallStmt, expect_fail: bool = False,
                          parent_job_id: Optional[int] = None) -> bool:
        """Execute a task call from within a requires block."""
        task_name = task_call.task_name

        # Check for circular dependency
        if task_name in self.call_stack:
            raise ValueError(f"INVALID_PIPE: Circular dependency detected for task '{task_name}'")

        # Get task definition
        if task_name not in self.pipeline.tasks:
            raise ValueError(f"INVALID_PIPE: Undefined task '{task_name}'")

        task_def = self.pipeline.tasks[task_name]

        # Evaluate positional and named arguments
        from .evaluator import Evaluator
        evaluator = Evaluator(
            variables={},
            env_vars=self.env_vars,
            workspace=self.workspace
        )

        positional_args = [evaluator.evaluate_expr(arg) for arg in task_call.positional_args]
        named_args = {name: evaluator.evaluate_expr(value) for name, value in task_call.named_args.items()}

        # Execute the task
        result = self.execute_task(task_def, positional_args, named_args, parent_job_id)

        # Check if result matches expectation
        success = result.exit_code == 0 and all(result.success.values()) if result.success else result.exit_code == 0

        if expect_fail:
            return not success
        return success

    def execute_task(self, task: TaskDef, positional_args: List[Any],
                     named_args: Dict[str, Any], parent_job_id: Optional[int] = None) -> JobResult:
        """Execute a task and return the result."""
        self.job_counter += 1
        job_id = self.job_counter

        start_time = time.time()

        # Validate and get parameters
        params = self.validate_params(task, positional_args, named_args)

        # Log task started
        self.log_event("TASK_STARTED", job_id, task=task.name, params=params)

        stdout = ""
        stderr = ""
        exit_code = 0
        timed_out = False
        success_results = {}
        output_dir = None

        try:
            # Check for recursion
            if task.name in self.call_stack:
                raise ValueError(f"INVALID_PIPE: Recursive call to task '{task.name}'")
            self.call_stack.add(task.name)

            # Resolve output directory
            output_dir = self.resolve_output_path(task.output, params)
            if output_dir and not self.validate_path_in_workspace(output_dir):
                raise ValueError(f"INVALID_PIPE: Output path '{output_dir}' escapes workspace")

            # Execute requires block first
            if task.requires_block:
                requires_evaluator = RequiresEvaluator(
                    variables={'params': params},
                    env_vars=self.env_vars,
                    workspace=self.workspace,
                    output_dir=output_dir,
                    task_executor=lambda tc, expect_fail=False: self.execute_task_call(tc, expect_fail, job_id)
                )

                for stmt in task.requires_block:
                    try:
                        requires_evaluator.evaluate_stmt(stmt)
                    except Exception as e:
                        if "Task call failed" in str(e) or "Expected task to fail" in str(e):
                            raise
                        # For other errors, we continue (the requires might have failed() wrapper)

            # Log task running
            self.log_event("TASK_RUNNING", job_id, task=task.name, params=params)

            # Execute run block
            if task.run_block:
                # Setup working directory
                if output_dir:
                    os.makedirs(output_dir, exist_ok=True)
                    cwd = output_dir
                else:
                    cwd = self.workspace

                # Clean cwd if needed
                if self.clean_cwd and output_dir:
                    for item in os.listdir(output_dir):
                        item_path = os.path.join(output_dir, item)
                        if os.path.isfile(item_path):
                            os.remove(item_path)
                        else:
                            shutil.rmtree(item_path)

                # Resolve and run command
                command = self.resolve_run_command(task.run_block, params, output_dir)
                stdout, stderr, exit_code, timed_out = self.run_command(
                    command, cwd, task.timeout
                )

            # Evaluate success block
            if task.success_block:
                success_evaluator = SuccessEvaluator(
                    variables={'params': params},
                    env_vars=self.env_vars,
                    workspace=self.workspace,
                    output_dir=output_dir,
                    stdout=stdout,
                    stderr=stderr,
                    exit_code=exit_code
                )

                for name, block in task.success_block.items():
                    try:
                        success_results[name] = success_evaluator.evaluate_success_block(block)
                    except Exception as e:
                        success_results[name] = False

            self.call_stack.discard(task.name)

        except Exception as e:
            self.call_stack.discard(task.name)
            stderr = str(e)
            exit_code = 1

        duration = time.time() - start_time

        # Determine overall success
        overall_success = exit_code == 0 and all(success_results.values()) if success_results else exit_code == 0

        result = JobResult(
            job_id=job_id,
            task=task.name,
            params=params,
            stdout=stdout,
            stderr=stderr,
            timed_out=timed_out,
            success=success_results,
            output=os.path.relpath(output_dir, self.workspace) if output_dir else None,
            exit_code=exit_code,
            parent=parent_job_id,
            duration=round(duration, 4)
        )

        self.job_results.append(result)

        # Log completion or failure
        if overall_success:
            self.log_event("TASK_COMPLETED", job_id, task=task.name, params=params)
        else:
            self.log_event("TASK_FAILED", job_id, task=task.name, params=params)

        return result

    def write_results(self):
        """Write job results to jobs.jsonl."""
        os.makedirs(self.output_dir, exist_ok=True)
        results_path = os.path.join(self.output_dir, "jobs.jsonl")

        with open(results_path, 'w') as f:
            for result in self.job_results:
                f.write(json.dumps(result.to_dict()) + '\n')

"""
Expression evaluator for the pipeline DSL.
"""

import os
import re
import subprocess
from typing import Any, Dict, List, Optional, Tuple
from .ast_nodes import (
    Expr, Stmt, IntLiteral, FloatLiteral, StringLiteral, BoolLiteral,
    ListLiteral, IdentifierExpr, ArrayIndexExpr, DollarVar, BinaryExpr,
    UnaryExpr, FunctionCallExpr, AssignmentExpr, ExprStmt, ReturnStmt,
    BreakStmt, ContinueStmt, BlockStmt, IfStmt, ForStmt, WhileStmt,
    TaskCallStmt, FailsStmt, SuccessBlock
)


class ReturnValue(Exception):
    def __init__(self, value):
        self.value = value


class BreakException(Exception):
    pass


class ContinueException(Exception):
    pass


class Evaluator:
    def __init__(self, variables: Dict[str, Any] = None, env_vars: Dict[str, str] = None,
                 workspace: str = None, output_dir: str = None, stdout: str = "",
                 stderr: str = "", exit_code: int = 0, task_executor=None):
        self.variables = variables or {}
        self.env_vars = env_vars or {}
        self.workspace = workspace
        self.output_dir = output_dir
        self.stdout = stdout
        self.stderr = stderr
        self.exit_code = exit_code
        self.task_executor = task_executor  # For executing task calls in requires

    def evaluate_expr(self, expr: Expr) -> Any:
        if isinstance(expr, IntLiteral):
            return expr.value
        elif isinstance(expr, FloatLiteral):
            return expr.value
        elif isinstance(expr, StringLiteral):
            return self.resolve_string_interpolation(expr.value)
        elif isinstance(expr, BoolLiteral):
            return expr.value
        elif isinstance(expr, ListLiteral):
            return [self.evaluate_expr(e) for e in expr.elements]
        elif isinstance(expr, IdentifierExpr):
            name = expr.name
            if name in self.variables:
                return self.variables[name]
            # Handle built-in variables
            elif name == 'stdout':
                return self.stdout
            elif name == 'stderr':
                return self.stderr
            elif name == 'exit_code':
                return self.exit_code
            else:
                raise ValueError(f"INVALID_PIPE: Undefined variable '{name}'")
        elif isinstance(expr, ArrayIndexExpr):
            array = self.evaluate_expr(expr.array)
            index = self.evaluate_expr(expr.index)
            if not isinstance(array, (list, str)):
                raise ValueError(f"INVALID_PIPE: Cannot index non-array type")
            return array[int(index)]
        elif isinstance(expr, DollarVar):
            return self.resolve_dollar_var(expr.value)
        elif isinstance(expr, BinaryExpr):
            return self.evaluate_binary(expr)
        elif isinstance(expr, UnaryExpr):
            return self.evaluate_unary(expr)
        elif isinstance(expr, FunctionCallExpr):
            return self.evaluate_function(expr)
        elif isinstance(expr, AssignmentExpr):
            return self.evaluate_assignment(expr)
        else:
            raise ValueError(f"INVALID_PIPE: Unknown expression type: {type(expr)}")

    def resolve_string_interpolation(self, value: str) -> str:
        """Resolve ${...} patterns within string literals."""
        import re
        # Find all ${...} patterns and replace them
        pattern = r'\$\{[^}]+\}'

        def replace_match(match):
            matched = match.group(0)
            return str(self.resolve_dollar_var(matched))

        return re.sub(pattern, replace_match, value)

    def resolve_dollar_var(self, value: str) -> Any:
        """Resolve ${params.x} or $VAR patterns."""
        if value.startswith('${'):
            # Extract the variable path
            inner = value[2:-1]  # Remove ${ and }
            parts = inner.split('.')

            if parts[0] == 'params':
                if len(parts) < 2:
                    raise ValueError(f"INVALID_PIPE: Invalid parameter reference: {value}")
                param_name = parts[1]
                if param_name not in self.variables.get('params', {}):
                    raise ValueError(f"INVALID_PIPE: Undefined parameter '{param_name}'")
                result = self.variables['params'][param_name]
                # Handle nested access like params.x.field
                for part in parts[2:]:
                    if isinstance(result, dict):
                        result = result.get(part)
                    else:
                        raise ValueError(f"INVALID_PIPE: Cannot access '{part}' on non-dict type")
                return result
            elif parts[0] == 'workspace':
                return self.workspace
            elif parts[0] == 'output':
                return self.output_dir
            else:
                # Try to find in variables
                obj = self.variables.get(parts[0])
                if obj is None:
                    raise ValueError(f"INVALID_PIPE: Undefined variable '{parts[0]}'")
                for part in parts[1:]:
                    if isinstance(obj, dict):
                        obj = obj.get(part)
                    else:
                        raise ValueError(f"INVALID_PIPE: Cannot access '{part}' on non-dict type")
                return obj
        elif value.startswith('$'):
            # Simple environment variable
            var_name = value[1:]
            if var_name in self.env_vars:
                return self.env_vars[var_name]
            return os.environ.get(var_name, "")
        return value

    def evaluate_binary(self, expr: BinaryExpr) -> Any:
        left = self.evaluate_expr(expr.left)
        right = self.evaluate_expr(expr.right)

        op = expr.op

        if op == '+':
            return left + right
        elif op == '-':
            return left - right
        elif op == '*':
            return left * right
        elif op == '/':
            if isinstance(left, int) and isinstance(right, int):
                return left // right  # Integer division
            return left / right
        elif op == '%':
            if isinstance(left, str) or isinstance(right, str):
                # String concatenation
                return str(left) + str(right)
            return left % right
        elif op == '==':
            return left == right
        elif op == '!=':
            return left != right
        elif op == '<':
            return left < right
        elif op == '>':
            return left > right
        elif op == '<=':
            return left <= right
        elif op == '>=':
            return left >= right
        elif op == '&&':
            return bool(left) and bool(right)
        elif op == '||':
            return bool(left) or bool(right)
        else:
            raise ValueError(f"INVALID_PIPE: Unknown operator: {op}")

    def evaluate_unary(self, expr: UnaryExpr) -> Any:
        operand = self.evaluate_expr(expr.operand)

        if expr.op == '!':
            return not bool(operand)
        elif expr.op == '-':
            return -operand
        else:
            raise ValueError(f"INVALID_PIPE: Unknown unary operator: {expr.op}")

    def evaluate_function(self, expr: FunctionCallExpr) -> Any:
        name = expr.name
        args = [self.evaluate_expr(arg) for arg in expr.args]

        if name == 'len':
            if len(args) != 1:
                raise ValueError(f"INVALID_PIPE: len() takes exactly 1 argument")
            return len(args[0])
        elif name == 'contains':
            if len(args) != 2:
                raise ValueError(f"INVALID_PIPE: contains() takes exactly 2 arguments")
            source, pattern = args
            if source == 'stdout':
                source = self.stdout
            elif source == 'stderr':
                source = self.stderr
            # Check if it's a regex pattern
            try:
                if pattern.startswith('/') and pattern.endswith('/'):
                    # Regex pattern
                    regex_pattern = pattern[1:-1]
                    return bool(re.search(regex_pattern, source))
                else:
                    # Exact string match
                    return pattern in source
            except re.error:
                return pattern in source
        elif name == 'equals':
            if len(args) != 2:
                raise ValueError(f"INVALID_PIPE: equals() takes exactly 2 arguments")
            source, value = args
            if source == 'stdout':
                source = self.stdout
            elif source == 'stderr':
                source = self.stderr
            elif source == 'exit_code':
                source = str(self.exit_code)
            else:
                # Check if source is a file path
                potential_path = source
                if not os.path.isabs(potential_path):
                    potential_path = os.path.join(self.workspace, potential_path)
                if os.path.isfile(potential_path):
                    with open(potential_path, 'r') as f:
                        source = f.read()
            return str(source) == str(value)
        elif name == 'exists':
            if len(args) != 1:
                raise ValueError(f"INVALID_PIPE: exists() takes exactly 1 argument")
            path = args[0]
            # Make path absolute if relative
            if not os.path.isabs(path):
                path = os.path.join(self.workspace, path)
            return os.path.exists(path)
        else:
            raise ValueError(f"INVALID_PIPE: Unknown function: {name}")

    def evaluate_assignment(self, expr: AssignmentExpr) -> Any:
        value = self.evaluate_expr(expr.value)
        name = expr.name if isinstance(expr.name, str) else str(expr.name)
        self.variables[name] = value
        return value

    def evaluate_stmt(self, stmt: Stmt) -> Any:
        if isinstance(stmt, ExprStmt):
            return self.evaluate_expr(stmt.expr)
        elif isinstance(stmt, ReturnStmt):
            value = self.evaluate_expr(stmt.value)
            raise ReturnValue(value)
        elif isinstance(stmt, BreakStmt):
            raise BreakException()
        elif isinstance(stmt, ContinueStmt):
            raise ContinueException()
        elif isinstance(stmt, BlockStmt):
            result = None
            for s in stmt.statements:
                result = self.evaluate_stmt(s)
            return result
        elif isinstance(stmt, IfStmt):
            condition = self.evaluate_expr(stmt.condition)
            if condition:
                return self.evaluate_stmt(stmt.then_block)
            else:
                for elif_cond, elif_block in stmt.elif_clauses:
                    if self.evaluate_expr(elif_cond):
                        return self.evaluate_stmt(elif_block)
                if stmt.else_block:
                    return self.evaluate_stmt(stmt.else_block)
        elif isinstance(stmt, ForStmt):
            if stmt.init:
                self.evaluate_stmt(stmt.init)
            while stmt.condition is None or self.evaluate_expr(stmt.condition):
                try:
                    self.evaluate_stmt(stmt.body)
                except BreakException:
                    break
                except ContinueException:
                    pass
                if stmt.update:
                    self.evaluate_stmt(stmt.update)
            return None
        elif isinstance(stmt, WhileStmt):
            while self.evaluate_expr(stmt.condition):
                try:
                    self.evaluate_stmt(stmt.body)
                except BreakException:
                    break
                except ContinueException:
                    pass
            return None
        elif isinstance(stmt, TaskCallStmt):
            if self.task_executor:
                result = self.task_executor(stmt, expect_fail=False)
                if not result:
                    raise ValueError("Task call failed")
                return result
            raise ValueError("INVALID_PIPE: Task calls not supported in this context")
        elif isinstance(stmt, FailsStmt):
            if self.task_executor:
                result = self.task_executor(stmt.task_call, expect_fail=True)
                if not result:
                    raise ValueError("Expected task to fail but it succeeded")
                return result
            raise ValueError("INVALID_PIPE: Task calls not supported in this context")
        else:
            raise ValueError(f"INVALID_PIPE: Unknown statement type: {type(stmt)}")

    def evaluate_success_block(self, block: SuccessBlock) -> bool:
        """Evaluate a success block and return True/False."""
        try:
            for stmt in block.statements:
                result = self.evaluate_stmt(stmt)
            # If we get here without a return, the result is the last expression
            # For single-expression blocks, return the boolean value
            if len(block.statements) == 1 and isinstance(block.statements[0], ExprStmt):
                return bool(result)
            # For multi-line blocks without return, it's an error
            if block.is_multiline:
                raise ValueError("SYNTAX_ERROR: Multi-line success block must have a return statement")
            return True
        except ReturnValue as rv:
            return bool(rv.value)

    def evaluate_requires_block(self, statements: List[Stmt]) -> bool:
        """Evaluate requires block statements and return success."""
        try:
            for stmt in statements:
                self.evaluate_stmt(stmt)
            return True
        except ReturnValue:
            return False


class SuccessEvaluator(Evaluator):
    """Evaluator specifically for success blocks."""

    def __init__(self, variables: Dict[str, Any] = None, env_vars: Dict[str, str] = None,
                 workspace: str = None, output_dir: str = None, stdout: str = "",
                 stderr: str = "", exit_code: int = 0):
        super().__init__(
            variables=variables,
            env_vars=env_vars,
            workspace=workspace,
            output_dir=output_dir,
            stdout=stdout,
            stderr=stderr,
            exit_code=exit_code,
            task_executor=None
        )


class RequiresEvaluator(Evaluator):
    """Evaluator for requires blocks with task execution support."""

    def __init__(self, variables: Dict[str, Any] = None, env_vars: Dict[str, str] = None,
                 workspace: str = None, output_dir: str = None, task_executor=None):
        super().__init__(
            variables=variables,
            env_vars=env_vars,
            workspace=workspace,
            output_dir=output_dir,
            task_executor=task_executor
        )

"""
Parser for the pipeline DSL.
"""

from typing import List, Optional, Dict, Any, Tuple
from .lexer import Lexer, Token, TokenType
from .ast_nodes import (
    Parameter, TaskDef, Pipeline, Expr, Stmt, BlockStmt,
    IntLiteral, FloatLiteral, StringLiteral, BoolLiteral, ListLiteral,
    IdentifierExpr, ArrayIndexExpr, DollarVar, BinaryExpr, UnaryExpr,
    FunctionCallExpr, AssignmentExpr, ExprStmt, ReturnStmt, BreakStmt,
    ContinueStmt, IfStmt, ForStmt, WhileStmt, TaskCallStmt, FailsStmt,
    SuccessBlock
)


class ParseError(Exception):
    pass


class Parser:
    def __init__(self, source: str):
        self.source = source
        self.lexer = Lexer(source)
        self.tokens = self.lexer.tokenize()
        self.pos = 0

    def error(self, msg: str):
        token = self.current()
        raise ParseError(f"SYNTAX_ERROR: {msg} at line {token.line}")

    def current(self) -> Token:
        if self.pos >= len(self.tokens):
            return self.tokens[-1]
        return self.tokens[self.pos]

    def peek(self, offset: int = 0) -> Token:
        pos = self.pos + offset
        if pos >= len(self.tokens):
            return self.tokens[-1]
        return self.tokens[pos]

    def advance(self) -> Token:
        token = self.current()
        self.pos += 1
        return token

    def match(self, *types: TokenType) -> bool:
        return self.current().type in types

    def expect(self, type: TokenType, msg: str = None) -> Token:
        if not self.match(type):
            self.error(msg or f"Expected {type}, got {self.current().type}")
        return self.advance()

    def skip_newlines(self):
        while self.match(TokenType.NEWLINE):
            self.advance()

    def parse(self) -> Pipeline:
        tasks = {}
        self.skip_newlines()
        while not self.match(TokenType.EOF):
            task = self.parse_task()
            tasks[task.name] = task
            self.skip_newlines()
        return Pipeline(tasks)

    def parse_task(self) -> TaskDef:
        self.expect(TokenType.TASK)
        name = self.expect(TokenType.IDENTIFIER).value
        self.skip_newlines()
        self.expect(TokenType.LBRACE)
        self.skip_newlines()

        params = []
        run_block = None
        success_block = None
        requires_block = None
        output = None
        timeout = None

        while not self.match(TokenType.RBRACE):
            if self.match(TokenType.PARAMS):
                self.advance()
                self.expect(TokenType.COLON)
                self.skip_newlines()
                self.expect(TokenType.LBRACE)
                self.skip_newlines()
                while not self.match(TokenType.RBRACE):
                    param = self.parse_parameter()
                    params.append(param)
                    if self.match(TokenType.SEMICOLON):
                        self.advance()
                    self.skip_newlines()
                self.expect(TokenType.RBRACE)
                self.skip_newlines()
            elif self.match(TokenType.RUN):
                self.advance()
                self.expect(TokenType.COLON)
                self.skip_newlines()
                run_block = self.parse_run_block()
                self.skip_newlines()
            elif self.match(TokenType.SUCCESS):
                self.advance()
                self.expect(TokenType.COLON)
                self.skip_newlines()
                success_block = self.parse_success_block()
                self.skip_newlines()
            elif self.match(TokenType.REQUIRES):
                self.advance()
                self.expect(TokenType.COLON)
                self.skip_newlines()
                requires_block = self.parse_requires_block()
                self.skip_newlines()
            elif self.match(TokenType.OUTPUT):
                self.advance()
                self.expect(TokenType.COLON)
                output = self.parse_expression()
                if self.match(TokenType.SEMICOLON):
                    self.advance()
                self.skip_newlines()
            elif self.match(TokenType.TIMEOUT):
                self.advance()
                self.expect(TokenType.COLON)
                timeout_token = self.expect(TokenType.FLOAT) if self.match(TokenType.FLOAT) else self.expect(TokenType.INT)
                timeout = float(timeout_token.value)
                if self.match(TokenType.SEMICOLON):
                    self.advance()
                self.skip_newlines()
            else:
                self.error(f"Unexpected token in task: {self.current().type}")

        self.expect(TokenType.RBRACE)
        self.skip_newlines()

        # Validate: task must have run or requires
        if run_block is None and requires_block is None:
            self.error(f"Task '{name}' must have either 'run' or 'requires' field")

        return TaskDef(
            name=name,
            params=params,
            run_block=run_block,
            success_block=success_block,
            requires_block=requires_block,
            output=output,
            timeout=timeout
        )

    def parse_parameter(self) -> Parameter:
        name = self.expect(TokenType.IDENTIFIER).value
        self.expect(TokenType.COLON)
        type_name = self.parse_type_name()
        inner_type = None
        if type_name == 'list':
            self.expect(TokenType.LBRACKET)
            inner_type = self.parse_type_name()
            self.expect(TokenType.RBRACKET)

        has_default = False
        default_value = None
        env_var = None

        if self.match(TokenType.EQUALS):
            self.advance()
            has_default = True
            if self.match(TokenType.DOLLAR):
                # Environment variable
                dollar_token = self.advance()
                env_var = dollar_token.value
                default_value = None  # Will be resolved later
            else:
                default_value = self.parse_literal_value(type_name, inner_type)

        full_type = f"list[{inner_type}]" if inner_type else type_name
        return Parameter(
            name=name,
            type_name=full_type,
            inner_type=inner_type,
            default_value=default_value,
            has_default=has_default,
            env_var=env_var
        )

    def parse_type_name(self) -> str:
        if self.match(TokenType.STRING_TYPE):
            self.advance()
            return 'string'
        elif self.match(TokenType.INT_TYPE):
            self.advance()
            return 'int'
        elif self.match(TokenType.FLOAT_TYPE):
            self.advance()
            return 'float'
        elif self.match(TokenType.BOOL_TYPE):
            self.advance()
            return 'bool'
        elif self.match(TokenType.LIST_TYPE):
            self.advance()
            return 'list'
        else:
            self.error(f"Expected type name, got {self.current().type}")

    def parse_literal_value(self, type_name: str, inner_type: str = None) -> Any:
        if type_name == 'string':
            return self.expect(TokenType.STRING).value
        elif type_name == 'int':
            return self.expect(TokenType.INT).value
        elif type_name == 'float':
            if self.match(TokenType.INT):
                return float(self.advance().value)
            return self.expect(TokenType.FLOAT).value
        elif type_name == 'bool':
            if self.match(TokenType.TRUE):
                self.advance()
                return True
            elif self.match(TokenType.FALSE):
                self.advance()
                return False
            else:
                self.error(f"Expected boolean value")
        elif type_name == 'list':
            self.expect(TokenType.LBRACKET)
            elements = []
            while not self.match(TokenType.RBRACKET):
                elements.append(self.parse_literal_value(inner_type))
                if self.match(TokenType.COMMA):
                    self.advance()
            self.expect(TokenType.RBRACKET)
            return elements
        else:
            self.error(f"Unknown type: {type_name}")

    def parse_run_block(self) -> str:
        """Parse run block - extract raw shell commands preserving original formatting."""
        # Record the position before the { token
        self.expect(TokenType.LBRACE)

        # Now we need to find the matching } and extract raw text from source
        # Track positions
        start_pos = self.current().start_pos if hasattr(self.current(), 'start_pos') else 0

        # Count braces to find the matching close
        depth = 1
        tokens_start = self.pos

        while depth > 0 and not self.match(TokenType.EOF):
            if self.match(TokenType.LBRACE):
                depth += 1
            elif self.match(TokenType.RBRACE):
                depth -= 1
                if depth == 0:
                    break
            self.advance()

        # Now we have the end position
        tokens_end = self.pos

        # Get the source positions from the tokens
        if tokens_start < len(self.tokens) and tokens_end < len(self.tokens):
            start_token = self.tokens[tokens_start]
            end_token = self.tokens[tokens_end]

            # Extract from source using positions
            if hasattr(start_token, 'start_pos') and hasattr(end_token, 'start_pos'):
                raw_text = self.source[start_token.start_pos:end_token.start_pos].strip()
            else:
                raw_text = ""
        else:
            raw_text = ""

        # Reset position to process tokens properly
        self.pos = tokens_start

        # Actually consume all the tokens until we reach the RBRACE
        depth = 1
        while depth > 0:
            if self.match(TokenType.LBRACE):
                depth += 1
                self.advance()
            elif self.match(TokenType.RBRACE):
                depth -= 1
                if depth == 0:
                    self.advance()
                    break
                self.advance()
            else:
                self.advance()

        return raw_text

    def parse_success_block(self) -> Dict[str, SuccessBlock]:
        """Parse success block - mapping of names to expression blocks."""
        self.expect(TokenType.LBRACE)
        self.skip_newlines()

        blocks = {}
        while not self.match(TokenType.RBRACE):
            name = self.expect(TokenType.IDENTIFIER).value
            self.expect(TokenType.COLON)
            self.skip_newlines()

            # Check if it's a block (with braces) or a simple expression
            if self.match(TokenType.LBRACE):
                # Multi-line block
                self.expect(TokenType.LBRACE)
                self.skip_newlines()
                statements = []
                while not self.match(TokenType.RBRACE):
                    stmt = self.parse_statement()
                    statements.append(stmt)
                    self.skip_newlines()
                self.expect(TokenType.RBRACE)
                self.skip_newlines()

                is_multiline = len(statements) > 1 or (len(statements) == 1 and isinstance(statements[0], ReturnStmt))
                blocks[name] = SuccessBlock(statements=statements, is_multiline=is_multiline)
            else:
                # Simple expression
                expr = self.parse_expression()
                if self.match(TokenType.SEMICOLON):
                    self.advance()
                self.skip_newlines()
                blocks[name] = SuccessBlock(
                    statements=[ExprStmt(expr)],
                    is_multiline=False
                )

        self.expect(TokenType.RBRACE)
        return blocks

    def parse_requires_block(self) -> List[Stmt]:
        """Parse requires block - list of statements."""
        self.expect(TokenType.LBRACE)
        self.skip_newlines()

        statements = []
        while not self.match(TokenType.RBRACE):
            stmt = self.parse_requires_statement()
            if stmt:
                statements.append(stmt)
            self.skip_newlines()

        self.expect(TokenType.RBRACE)
        return statements

    def parse_requires_statement(self) -> Optional[Stmt]:
        """Parse a statement in requires block."""
        if self.match(TokenType.FAILS):
            return self.parse_fails_statement()
        elif self.match(TokenType.FAIL):
            return self.parse_fail_statement()
        elif self.match(TokenType.IF):
            return self.parse_if_statement()
        elif self.match(TokenType.FOR):
            return self.parse_for_statement()
        elif self.match(TokenType.WHILE):
            return self.parse_while_statement()
        elif self.match(TokenType.IDENTIFIER):
            # Could be task call or variable declaration
            if self.peek(1).type == TokenType.LPAREN:
                # Task call
                return self.parse_task_call()
            elif self.peek(1).type == TokenType.IDENTIFIER:
                # Variable declaration: type name = value
                return self.parse_variable_declaration()
            else:
                # Expression statement
                expr = self.parse_expression()
                if self.match(TokenType.SEMICOLON):
                    self.advance()
                return ExprStmt(expr)
        else:
            expr = self.parse_expression()
            if self.match(TokenType.SEMICOLON):
                self.advance()
            return ExprStmt(expr)

    def parse_statement(self) -> Stmt:
        """Parse a statement in success block."""
        if self.match(TokenType.RETURN):
            self.advance()
            value = self.parse_expression()
            if self.match(TokenType.SEMICOLON):
                self.advance()
            return ReturnStmt(value)
        elif self.match(TokenType.IF):
            return self.parse_if_statement()
        elif self.match(TokenType.FOR):
            return self.parse_for_statement()
        elif self.match(TokenType.WHILE):
            return self.parse_while_statement()
        elif self.match(TokenType.BREAK):
            self.advance()
            if self.match(TokenType.SEMICOLON):
                self.advance()
            return BreakStmt()
        elif self.match(TokenType.CONTINUE):
            self.advance()
            if self.match(TokenType.SEMICOLON):
                self.advance()
            return ContinueStmt()
        else:
            expr = self.parse_expression()
            if self.match(TokenType.SEMICOLON):
                self.advance()
            return ExprStmt(expr)

    def parse_fails_statement(self) -> FailsStmt:
        self.expect(TokenType.FAILS)
        self.expect(TokenType.LPAREN)
        task_call = self.parse_task_call()
        self.expect(TokenType.RPAREN)
        if self.match(TokenType.SEMICOLON):
            self.advance()
        return FailsStmt(task_call)

    def parse_fail_statement(self) -> FailsStmt:
        self.expect(TokenType.FAIL)
        self.expect(TokenType.LPAREN)
        task_call = self.parse_task_call()
        self.expect(TokenType.RPAREN)
        if self.match(TokenType.SEMICOLON):
            self.advance()
        return FailsStmt(task_call)

    def parse_task_call(self) -> TaskCallStmt:
        name = self.expect(TokenType.IDENTIFIER).value
        self.expect(TokenType.LPAREN)

        positional_args = []
        named_args = {}

        while not self.match(TokenType.RPAREN):
            # Check if it's a named arg
            if self.match(TokenType.IDENTIFIER) and self.peek(1).type == TokenType.EQUALS:
                arg_name = self.advance().value
                self.expect(TokenType.EQUALS)
                arg_value = self.parse_expression()
                named_args[arg_name] = arg_value
            else:
                positional_args.append(self.parse_expression())

            if self.match(TokenType.COMMA):
                self.advance()

        self.expect(TokenType.RPAREN)
        if self.match(TokenType.SEMICOLON):
            self.advance()

        return TaskCallStmt(task_name=name, positional_args=positional_args, named_args=named_args)

    def parse_variable_declaration(self) -> AssignmentExpr:
        """Parse: type name = value;"""
        type_name = self.parse_type_name()
        name = self.expect(TokenType.IDENTIFIER).value
        self.expect(TokenType.EQUALS)
        value = self.parse_expression()
        if self.match(TokenType.SEMICOLON):
            self.advance()
        return AssignmentExpr(type_name=type_name, name=name, value=value)

    def parse_if_statement(self) -> IfStmt:
        self.expect(TokenType.IF)
        self.expect(TokenType.LPAREN)
        condition = self.parse_expression()
        self.expect(TokenType.RPAREN)
        self.skip_newlines()
        then_block = self.parse_block()

        elif_clauses = []
        else_block = None

        while self.match(TokenType.ELIF):
            self.advance()
            self.expect(TokenType.LPAREN)
            elif_cond = self.parse_expression()
            self.expect(TokenType.RPAREN)
            self.skip_newlines()
            elif_block = self.parse_block()
            elif_clauses.append((elif_cond, elif_block))

        if self.match(TokenType.ELSE):
            self.advance()
            self.skip_newlines()
            else_block = self.parse_block()

        return IfStmt(condition=condition, then_block=then_block, elif_clauses=elif_clauses, else_block=else_block)

    def parse_for_statement(self) -> ForStmt:
        self.expect(TokenType.FOR)
        self.expect(TokenType.LPAREN)

        # Parse init
        init = None
        if not self.match(TokenType.SEMICOLON):
            if self.match(TokenType.IDENTIFIER):
                # Check if it's a declaration
                if self.peek(1).type in (TokenType.STRING_TYPE, TokenType.INT_TYPE,
                                          TokenType.FLOAT_TYPE, TokenType.BOOL_TYPE,
                                          TokenType.LIST_TYPE, TokenType.IDENTIFIER):
                    # Could be "int i = 0" pattern - need to look ahead more
                    pass
            # Try to parse as declaration first
            saved_pos = self.pos
            try:
                if self.match(TokenType.INT_TYPE, TokenType.FLOAT_TYPE, TokenType.BOOL_TYPE,
                              TokenType.STRING_TYPE, TokenType.LIST_TYPE):
                    init = self.parse_variable_declaration()
                else:
                    init = self.parse_expression()
                    if self.match(TokenType.SEMICOLON):
                        self.advance()
                    init = ExprStmt(init)
            except:
                self.pos = saved_pos
                init = self.parse_expression()
                if self.match(TokenType.SEMICOLON):
                    self.advance()
                init = ExprStmt(init)
        else:
            self.advance()  # skip ;

        if init is None:
            self.expect(TokenType.SEMICOLON)

        # Parse condition
        condition = None
        if not self.match(TokenType.SEMICOLON):
            condition = self.parse_expression()
        self.expect(TokenType.SEMICOLON)

        # Parse update
        update = None
        if not self.match(TokenType.RPAREN):
            update_expr = self.parse_expression()
            if self.match(TokenType.SEMICOLON):
                self.advance()
            update = ExprStmt(update_expr)

        self.expect(TokenType.RPAREN)
        self.skip_newlines()
        body = self.parse_block()

        return ForStmt(init=init, condition=condition, update=update, body=body)

    def parse_while_statement(self) -> WhileStmt:
        self.expect(TokenType.WHILE)
        self.expect(TokenType.LPAREN)
        condition = self.parse_expression()
        self.expect(TokenType.RPAREN)
        self.skip_newlines()
        body = self.parse_block()
        return WhileStmt(condition=condition, body=body)

    def parse_block(self) -> BlockStmt:
        self.expect(TokenType.LBRACE)
        self.skip_newlines()

        statements = []
        while not self.match(TokenType.RBRACE):
            stmt = self.parse_statement()
            statements.append(stmt)
            self.skip_newlines()

        self.expect(TokenType.RBRACE)
        return BlockStmt(statements=statements)

    def parse_expression(self) -> Expr:
        return self.parse_or_expression()

    def parse_or_expression(self) -> Expr:
        left = self.parse_and_expression()
        while self.match(TokenType.OR):
            op = self.advance().type
            right = self.parse_and_expression()
            left = BinaryExpr(op='||', left=left, right=right)
        return left

    def parse_and_expression(self) -> Expr:
        left = self.parse_equality_expression()
        while self.match(TokenType.AND):
            op = self.advance().type
            right = self.parse_equality_expression()
            left = BinaryExpr(op='&&', left=left, right=right)
        return left

    def parse_equality_expression(self) -> Expr:
        left = self.parse_comparison_expression()
        while self.match(TokenType.EQ, TokenType.NEQ):
            op = '==' if self.advance().type == TokenType.EQ else '!='
            right = self.parse_comparison_expression()
            left = BinaryExpr(op=op, left=left, right=right)
        return left

    def parse_comparison_expression(self) -> Expr:
        left = self.parse_additive_expression()
        while self.match(TokenType.LT, TokenType.GT, TokenType.LTE, TokenType.GTE):
            token = self.advance()
            op_map = {
                TokenType.LT: '<',
                TokenType.GT: '>',
                TokenType.LTE: '<=',
                TokenType.GTE: '>='
            }
            op = op_map[token.type]
            right = self.parse_additive_expression()
            left = BinaryExpr(op=op, left=left, right=right)
        return left

    def parse_additive_expression(self) -> Expr:
        left = self.parse_multiplicative_expression()
        while self.match(TokenType.PLUS, TokenType.MINUS, TokenType.PERCENT):
            token = self.advance()
            op_map = {
                TokenType.PLUS: '+',
                TokenType.MINUS: '-',
                TokenType.PERCENT: '%'
            }
            op = op_map[token.type]
            right = self.parse_multiplicative_expression()
            left = BinaryExpr(op=op, left=left, right=right)
        return left

    def parse_multiplicative_expression(self) -> Expr:
        left = self.parse_unary_expression()
        while self.match(TokenType.STAR, TokenType.SLASH):
            token = self.advance()
            op = '*' if token.type == TokenType.STAR else '/'
            right = self.parse_unary_expression()
            left = BinaryExpr(op=op, left=left, right=right)
        return left

    def parse_unary_expression(self) -> Expr:
        if self.match(TokenType.NOT, TokenType.MINUS):
            token = self.advance()
            op = '!' if token.type == TokenType.NOT else '-'
            operand = self.parse_unary_expression()
            return UnaryExpr(op=op, operand=operand)
        return self.parse_primary_expression()

    def parse_primary_expression(self) -> Expr:
        if self.match(TokenType.INT):
            return IntLiteral(self.advance().value)
        elif self.match(TokenType.FLOAT):
            return FloatLiteral(self.advance().value)
        elif self.match(TokenType.STRING):
            return StringLiteral(self.advance().value)
        elif self.match(TokenType.TRUE):
            self.advance()
            return BoolLiteral(True)
        elif self.match(TokenType.FALSE):
            self.advance()
            return BoolLiteral(False)
        elif self.match(TokenType.DOLLAR):
            return DollarVar(self.advance().value)
        elif self.match(TokenType.LBRACKET):
            return self.parse_list_literal()
        elif self.match(TokenType.LPAREN):
            self.advance()
            expr = self.parse_expression()
            self.expect(TokenType.RPAREN)
            return expr
        elif self.match(TokenType.IDENTIFIER):
            name = self.advance().value

            # Check for function call
            if self.match(TokenType.LPAREN):
                self.advance()
                args = []
                while not self.match(TokenType.RPAREN):
                    args.append(self.parse_expression())
                    if self.match(TokenType.COMMA):
                        self.advance()
                self.expect(TokenType.RPAREN)
                return FunctionCallExpr(name=name, args=args)

            # Check for array index
            while self.match(TokenType.LBRACKET):
                self.advance()
                index = self.parse_expression()
                self.expect(TokenType.RBRACKET)
                name = ArrayIndexExpr(array=IdentifierExpr(name), index=index) if isinstance(name, str) else ArrayIndexExpr(array=name, index=index)

            # Check for assignment
            if self.match(TokenType.EQUALS):
                self.advance()
                value = self.parse_expression()
                return AssignmentExpr(type_name=None, name=name if isinstance(name, str) else name, value=value)

            if isinstance(name, str):
                return IdentifierExpr(name)
            return name
        else:
            self.error(f"Unexpected token in expression: {self.current().type}")

    def parse_list_literal(self) -> ListLiteral:
        self.expect(TokenType.LBRACKET)
        elements = []
        while not self.match(TokenType.RBRACKET):
            elements.append(self.parse_expression())
            if self.match(TokenType.COMMA):
                self.advance()
        self.expect(TokenType.RBRACKET)
        return ListLiteral(elements=elements)

